mapper.select:
SELECT u.id AS id, u.login_name AS loginName, u.gender AS gender, us.username AS username, u.mobile_head AS mobileHead, u.mobile AS mobile, us.user_number AS userNumber, us.user_group_ids AS userGroupIds, udr.is_admin AS isDeptLeader, udr.is_master AS isMasterDept, d.id AS deptId, d.`name` AS deptName FROM ( SELECT user_id, dept_id, is_admin, is_master FROM sys_user_dept_rel WHERE school_id = ${schoolId} AND deleted = 0
AND dept_id = ${reqModel.deptId}
AND is_master = 1
) udr LEFT JOIN ( SELECT username, user_id, user_number, id, user_group_ids,create_time FROM sys_user_school_rel WHERE school_id = ${schoolId} AND deleted = 0 ) us ON udr.user_id = us.id LEFT JOIN sys_user u ON us.user_id = u.id LEFT JOIN ( SELECT `name`, id FROM sys_dept WHERE school_id = ${schoolId} AND deleted = 0 ) d ON d.id = udr.dept_id WHERE u.deleted = 0
AND ( us.username LIKE CONCAT('%', #{reqModel.searchText}, '%') OR us.user_number LIKE CONCAT('%', #{reqModel.searchText}, '%') OR u.mobile LIKE CONCAT('%', #{reqModel.searchText}, '%') OR u.login_name LIKE CONCAT('%', #{reqModel.searchText}, '%') )
AND us.user_group_ids LIKE CONCAT('%', #{reqModel.groupId}, '%')
AND u.gender = ${reqModel.gender}
ORDER BY us.create_time DESC
